# Category: serverless_security

import azure.functions as func
import json
import logging
from azure.storage.blob import BlobServiceClient
from azure.cosmos import CosmosClient
from azure.eventgrid import EventGridPublisherClient
from azure.core.credentials import AzureCredential
from azure.identity import ManagedIdentityCredential

# Initialize Managed Identity Credential
# If running in Azure, the system-assigned managed identity will be picked up automatically.
# For local development with a user-assigned managed identity, specify its client ID:
# credential = ManagedIdentityCredential(client_id="<YOUR_USER_ASSIGNED_MANAGED_IDENTITY_CLIENT_ID>")
credential = ManagedIdentityCredential()

# --- Configuration (Replace with your actual resource names/URIs) ---
# Blob Storage
BLOB_STORAGE_ACCOUNT_URL = "https://<YOUR_STORAGE_ACCOUNT_NAME>.blob.core.windows.net"
BLOB_OUTPUT_CONTAINER_NAME = "processed-results"

# Cosmos DB
COSMOS_DB_ENDPOINT = "https://<YOUR_COSMOS_DB_ACCOUNT_NAME>.documents.azure.com:443/"
COSMOS_DB_DATABASE_NAME = "MyProcessedDataDB"
COSMOS_DB_CONTAINER_NAME = "ProcessedFiles"

# Event Grid
EVENT_GRID_TOPIC_ENDPOINT = "https://<YOUR_EVENT_GRID_TOPIC_NAME>.westus2-1.eventgrid.azure.net/api/events"
EVENT_GRID_TOPIC_KEY = None # Not needed with Managed Identity, leave as None
# For Event Grid with Managed Identity, the credential is used implicitly by the client.
# You might need to specify the resource_id if your topic isn't in the same subscription/resource group as the function.
# However, for simplicity and MVP, the default behavior often works if permissions are broad.

# Initialize Azure Service Clients using Managed Identity
blob_service_client = BlobServiceClient(account_url=BLOB_STORAGE_ACCOUNT_URL, credential=credential)
cosmos_client = CosmosClient(url=COSMOS_DB_ENDPOINT, credential=credential)
event_grid_publisher = EventGridPublisherClient(endpoint=EVENT_GRID_TOPIC_ENDPOINT, credential=credential)

# Get Cosmos DB database and container objects
cosmos_database = cosmos_client.get_database_client(COSMOS_DB_DATABASE_NAME)
cosmos_container = cosmos_database.get_container_client(COSMOS_DB_CONTAINER_NAME)
# -------------------------------------------------------------------

app = func.FunctionApp()

@app.blob_trigger(
    name="inputblob",
    path="input-files/{name}", # Trigger on files uploaded to 'input-files' container
    connection="AzureWebJobsStorage" # Use the connection string specified in local.settings.json / App Settings
)
def process_blob_function(inputblob: func.InputStream, name: str):
    logging.info(f"Python blob trigger function processed blob\n"
                 f"Name: {inputblob.name}\n"
                 f"Size: {inputblob.length} Bytes")

    try:
        # --- 1. Process the blob content ---
        blob_content = inputblob.read().decode('utf-8')
        logging.info(f"Processing content for {name}: {blob_content[:100]}...") # Log first 100 chars

        # Example processing: Just reverse the content
        processed_content = blob_content[::-1]
        processing_result = {
            "originalFileName": name,
            "originalUri": inputblob.uri,
            "processedContent": processed_content,
            "timestamp": func.get_current_utc_timestamp().isoformat()
        }

        # --- 2. Write results to Cosmos DB ---
        cosmos_item_id = inputblob.name.split('/')[-1].replace('.', '-') # Create a simple ID
        cosmos_item = {
            "id": cosmos_item_id,
            "fileName": name,
            "originalUri": inputblob.uri,
            "processedResult": processing_result,
            "status": "Processed",
            "processTime": func.get_current_utc_timestamp().isoformat()
        }
        cosmos_container.upsert_item(body=cosmos_item)
        logging.info(f"Wrote result for {name} to Cosmos DB with ID: {cosmos_item_id}")

        # --- 3. Write processed content back to Blob Storage (optional, but good for MVP) ---
        output_blob_client = blob_service_client.get_blob_client(
            container=BLOB_OUTPUT_CONTAINER_NAME,
            blob=f"{name}-processed.txt"
        )
        output_blob_client.upload_blob(processed_content, overwrite=True)
        logging.info(f"Wrote processed content for {name} to output blob storage.")

        # --- 4. Send notification via Event Grid ---
        event_data = {
            "id": func.new_guid().hex,
            "topic": "/subscriptions/<YOUR_SUBSCRIPTION_ID>/resourceGroups/<YOUR_RESOURCE_GROUP>/providers/Microsoft.EventGrid/topics/<YOUR_EVENT_GRID_TOPIC_NAME>", # Fully qualified topic path
            "subject": f"/blob/processed/{name}",
            "data": {
                "fileName": name,
                "originalUri": inputblob.uri,
                "cosmosDbItemId": cosmos_item_id,
                "status": "Success",
                "processedBlobUri": output_blob_client.url if output_blob_client else None
            },
            "eventType": "BlobProcessedEvent",
            "dataVersion": "1.0",
            "eventTime": func.get_current_utc_timestamp().isoformat()
        }
        event_grid_publisher.send([event_data])
        logging.info(f"Sent Event Grid notification for {name}.")

    except Exception as e:
        logging.error(f"Error processing blob {name}: {e}")
        # Optionally send a failure notification
        error_event_data = {
            "id": func.new_guid().hex,
            "topic": "/subscriptions/<YOUR_SUBSCRIPTION_ID>/resourceGroups/<YOUR_RESOURCE_GROUP>/providers/Microsoft.EventGrid/topics/<YOUR_EVENT_GRID_TOPIC_NAME>",
            "subject": f"/blob/processing-failed/{name}",
            "data": {
                "fileName": name,
                "originalUri": inputblob.uri,
                "status": "Failed",
                "errorMessage": str(e)
            },
            "eventType": "BlobProcessingFailedEvent",
            "dataVersion": "1.0",
            "eventTime": func.get_current_utc_timestamp().isoformat()
        }
        event_grid_publisher.send([error_event_data])
        logging.info(f"Sent Event Grid failure notification for {name}.")
        raise # Re-raise the exception to indicate function failure